#include <stdio.h>
#include <limits.h>

int findOptimal(int frames[], int numFrames, int refString[], 
                int currentIndex, int numReferences) {
    int optimalIndex = -1;
    int farthest = -1;

    for (int i = 0; i < numFrames; i++) {
        int j;
        // Find when this page will be used next
        for (j = currentIndex; j < numReferences; j++) {
            if (frames[i] == refString[j]) {
                break;
            }
        }
        // If page never used again, optimal choice
        if (j == numReferences) {
            return i;
        }
        // Track farthest use
        if (j > farthest) {
            farthest = j;
            optimalIndex = i;
        }
    }
    return optimalIndex;
}

int optimalPageReplacement(int refString[], int numReferences, 
                            int numFrames) {
    int frames[numFrames];
    int pageFaults = 0;

    // Initialize frames to -1 (empty)
    for (int i = 0; i < numFrames; i++) {
        frames[i] = -1;
    }

    for (int i = 0; i < numReferences; i++) {
        int page = refString[i];
        int pageFound = 0;

        // Check if page is already in frames
        for (int j = 0; j < numFrames; j++) {
            if (frames[j] == page) {
                pageFound = 1;
                break;
            }
        }

        if (!pageFound) {
            pageFaults++;

            // Find empty frame or optimal victim
            for (int j = 0; j < numFrames; j++) {
                if (frames[j] == -1) {
                    frames[j] = page;
                    pageFound = 1;
                    break;
                }
            }

            if (!pageFound) {
                int victimIndex = findOptimal(frames, numFrames, 
                                   refString, i, numReferences);
                frames[victimIndex] = page;
            }
        }
    }
    return pageFaults;
}

int main() {
    int refString[] = {1, 2, 3, 4, 1, 2, 5};
    int numReferences = 7;
    int numFrames = 3;

    int faults = optimalPageReplacement(refString, numReferences, 
                                        numFrames);
    printf("Optimal Page Faults: %d\n", faults);
    return 0;
}
